import{_ as t,o as a,c as i,a0 as r}from"./chunks/framework.jwovEGr5.js";const u=JSON.parse('{"title":"Participant Eligibility Statuses","description":"","frontmatter":{},"headers":[],"relativePath":"reference/participant-eligibility.md","filePath":"reference/participant-eligibility.md"}'),s={name:"reference/participant-eligibility.md"};function l(n,e,o,h,d,c){return a(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="participant-eligibility-statuses" tabindex="-1">Participant Eligibility Statuses <a class="header-anchor" href="#participant-eligibility-statuses" aria-label="Permalink to &quot;Participant Eligibility Statuses&quot;">​</a></h1><p>An event instance can mark players with different eligibility states. These statuses help reviewers understand whether a saved or imported row clearly belongs in the event snapshot.</p><h2 id="the-seven-statuses" tabindex="-1">The seven statuses <a class="header-anchor" href="#the-seven-statuses" aria-label="Permalink to &quot;The seven statuses&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Status</th><th>Plain meaning</th></tr></thead><tbody><tr><td><code>Eligible</code></td><td>The player cleanly belongs in this event snapshot.</td></tr><tr><td><code>Left during event</code></td><td>The player left during the event window, so later rows may need care.</td></tr><tr><td><code>Joined after start</code></td><td>The player was first seen after the instance had already started.</td></tr><tr><td><code>Transferred</code></td><td>The player&#39;s current alliance differs from the event alliance.</td></tr><tr><td><code>No alliance</code></td><td>The player currently has no alliance.</td></tr><tr><td><code>Not eligible</code></td><td>The current rules say this player should not count automatically.</td></tr><tr><td><code>Needs review</code></td><td>The tracker could not safely decide without a human check.</td></tr></tbody></table><h2 id="why-these-appear" tabindex="-1">Why these appear <a class="header-anchor" href="#why-these-appear" aria-label="Permalink to &quot;Why these appear&quot;">​</a></h2><p>These statuses are shaped by the event&#39;s policy settings, especially:</p><ul><li>snapshot mode</li><li>new joiner policy</li><li>membership change policy</li><li>leave policy</li></ul><p>Those are configured in <a href="./../how-to/event-settings.html">Configure Event Settings</a>.</p><h2 id="how-to-use-them" tabindex="-1">How to use them <a class="header-anchor" href="#how-to-use-them" aria-label="Permalink to &quot;How to use them&quot;">​</a></h2><ul><li>treat <strong>Eligible</strong> as clean</li><li>treat everything else as a sign to review the event context more carefully</li><li>do not assume <strong>Transferred</strong> means the score should move to the new alliance</li></ul><p>In fact, transfer cases are often kept with the original event alliance and flagged for review.</p><h2 id="where-you-see-them" tabindex="-1">Where you see them <a class="header-anchor" href="#where-you-see-them" aria-label="Permalink to &quot;Where you see them&quot;">​</a></h2><p>Eligibility appears on instance detail pages, especially in the participant snapshot section.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./../how-to/instance-detail.html">Work Inside an Instance</a></li><li><a href="./../how-to/event-settings.html">Configure Event Settings</a></li></ul>',15)])])}const y=t(s,[["render",l]]);export{u as __pageData,y as default};
